// MITRE ATT&CK Lookup Node for n8n
// Paste this code into an n8n Code node
// Reads MITRE ATT&CK techniques from JSON and matches against analyst findings

const fs = require('fs');

// Read the MITRE ATT&CK techniques database
const techniquesData = JSON.parse(
  fs.readFileSync('/home/node/assets/mitre-attack-techniques.json', 'utf8')
);

// Get analyst findings from upstream nodes
const inputData = $input.all();
const findings = inputData.map(item => {
  // Handle both direct response text and structured objects
  if (typeof item.json === 'string') return item.json;
  if (item.json.response) return item.json.response;
  return JSON.stringify(item.json);
}).join(' ');

// Get investigation type if available (for boosting relevant tactics)
// Get investigation_type from the workflow trigger (not from Ollama response, which strips it)
let investigationType = 'general';
try {
  investigationType = $('Execute Workflow Trigger').first().json.investigation_type || 'general';
} catch (e) {
  // Fallback: check immediate input (works if data was passed through)
  investigationType = $input.first().json.investigation_type || 'general';
}

// Investigation-type-specific tactic boosting
const tacticBoosts = {
  'auth_anomaly': ['Credential Access', 'Initial Access', 'Privilege Escalation', 'Persistence'],
  'beaconing': ['Command and Control', 'Exfiltration', 'Defense Evasion'],
  'exfiltration': ['Exfiltration', 'Collection', 'Command and Control'],
  'lateral_movement': ['Lateral Movement', 'Discovery', 'Credential Access', 'Execution'],
  'general': []
};

const boostedTactics = tacticBoosts[investigationType] || [];

// Normalize text for keyword matching
function normalizeText(text) {
  return text.toLowerCase()
    .replace(/[^a-z0-9\s\-\.]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Extract meaningful terms from findings
const normalizedFindings = normalizeText(findings);
const findingsTerms = normalizedFindings.split(' ').filter(t => t.length > 2);

// Score each technique against the findings
const scoredTechniques = techniquesData.map(technique => {
  let score = 0;

  // Keyword matching
  for (const keyword of technique.keywords) {
    const normalizedKeyword = keyword.toLowerCase();
    // Check if the keyword (which may be multi-word) appears in findings
    if (normalizedFindings.includes(normalizedKeyword)) {
      score += normalizedKeyword.split(' ').length; // Multi-word matches score higher
    }
  }

  // Tactic boosting for investigation type
  if (boostedTactics.length > 0) {
    const tacticOverlap = technique.tactics.filter(t => boostedTactics.includes(t));
    score += tacticOverlap.length * 0.5; // Boost by 0.5 per matching tactic
  }

  // Name matching (technique name appears in findings)
  if (normalizedFindings.includes(technique.name.toLowerCase())) {
    score += 3;
  }

  // ID matching (technique ID explicitly mentioned)
  if (normalizedFindings.includes(technique.id.toLowerCase())) {
    score += 5;
  }

  return {
    id: technique.id,
    name: technique.name,
    tactics: technique.tactics,
    description: technique.description,
    detection: technique.detection,
    score: score
  };
}).filter(t => t.score > 0);

// Sort by score descending, take top 10
scoredTechniques.sort((a, b) => b.score - a.score);
const topTechniques = scoredTechniques.slice(0, 10);

// Build output
return [{
  json: {
    techniques: topTechniques,
    technique_count: topTechniques.length,
    investigation_type: investigationType,
    total_techniques_scanned: techniquesData.length,
    // Pass through the original findings for downstream nodes
    analyst_findings: findings
  }
}];

// NIST CSF 2.0 Mapping Node for n8n
// Paste this code into an n8n Code node
// Maps analyst findings to NIST CSF 2.0 functions and categories

const fs = require('fs');

// Read the NIST CSF 2.0 framework data
const csfData = JSON.parse(
  fs.readFileSync('/home/node/assets/nist-csf-2.0.json', 'utf8')
);

// Get findings from upstream (MITRE Lookup node passes analyst_findings through)
const inputData = $input.first().json;
const findings = inputData.analyst_findings || JSON.stringify(inputData);
const techniques = inputData.techniques || [];

// Normalize text for matching
const normalizedFindings = findings.toLowerCase()
  .replace(/[^a-z0-9\s\-\.]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Score each CSF category against findings
const mappings = [];

for (const func of csfData.functions) {
  for (const category of func.categories) {
    let score = 0;

    // Keyword matching against findings
    for (const keyword of (category.keywords || [])) {
      if (normalizedFindings.includes(keyword.toLowerCase())) {
        score += 1;
      }
    }

    // Category name matching
    if (normalizedFindings.includes(category.name.toLowerCase())) {
      score += 2;
    }

    // Boost based on MITRE technique tactics → CSF function correlation
    // DE (Detect) correlates with Discovery, Initial Access detection
    // RS (Respond) correlates with incident-related findings
    // PR (Protect) correlates with prevention-related findings
    const tacticToCsf = {
      'Initial Access': ['DE', 'PR'],
      'Execution': ['DE', 'PR'],
      'Persistence': ['DE', 'PR'],
      'Privilege Escalation': ['DE', 'PR', 'GV'],
      'Defense Evasion': ['DE'],
      'Credential Access': ['DE', 'PR', 'ID'],
      'Discovery': ['DE'],
      'Lateral Movement': ['DE', 'RS'],
      'Collection': ['DE', 'PR'],
      'Command and Control': ['DE', 'RS'],
      'Exfiltration': ['DE', 'RS', 'RC'],
      'Impact': ['RS', 'RC']
    };

    for (const technique of techniques) {
      for (const tactic of technique.tactics) {
        const correlatedFunctions = tacticToCsf[tactic] || [];
        if (correlatedFunctions.includes(func.id)) {
          score += 0.5;
        }
      }
    }

    if (score > 0) {
      mappings.push({
        function_id: func.id,
        function_name: func.name,
        category_id: category.id,
        category_name: category.name,
        description: category.description,
        score: score,
        relevant_subcategories: (category.subcategories || [])
          .map(sc => ({ id: sc.id, description: sc.description }))
      });
    }
  }
}

// Sort by score, take top matches
mappings.sort((a, b) => b.score - a.score);
const topMappings = mappings.slice(0, 8);

// Group by function for cleaner output
const byFunction = {};
for (const m of topMappings) {
  if (!byFunction[m.function_id]) {
    byFunction[m.function_id] = {
      function_id: m.function_id,
      function_name: m.function_name,
      categories: []
    };
  }
  byFunction[m.function_id].categories.push({
    category_id: m.category_id,
    category_name: m.category_name,
    description: m.description,
    relevant_subcategories: m.relevant_subcategories.slice(0, 3)
  });
}

return [{
  json: {
    nist_csf_mappings: Object.values(byFunction),
    total_mappings: topMappings.length,
    // Pass through upstream data for downstream nodes
    techniques: techniques,
    analyst_findings: findings
  }
}];

// NIST SP 800-92 Aligned Report Formatter for n8n
// Paste this code into an n8n Code node
// Takes synthesizer output + MITRE + NIST + CIS Controls + CAR coverage data
// and produces standardized investigation report
//
// v2.0.0 — Added CIS Controls v8.1.2 and MITRE CAR analytic coverage sections

// Gather data from upstream nodes
const synthesizerOutput = $input.first().json;

let techniques      = [];
let nistMappings    = [];
let cisMappings     = [];
let cisQuickWins    = [];
let coverageGaps    = [];
let lowCoverage     = [];
let analystFindings = '';
let investigationType = 'general';
let originalQuery   = '';

try {
  const mitreData     = $('MITRE Lookup').first().json;
  techniques          = mitreData.techniques        || [];
  analystFindings     = mitreData.analyst_findings  || '';
  investigationType   = mitreData.investigation_type || 'general';
} catch (e) {
  techniques = synthesizerOutput.techniques || [];
}

// Safety: if MITRE Lookup still says 'general', check the workflow trigger directly
if (investigationType === 'general') {
  try {
    const triggerType = $('Execute Workflow Trigger').first().json.investigation_type;
    if (triggerType && triggerType !== 'general') {
      investigationType = triggerType;
    }
  } catch (e) {
    // Trigger reference failed — keep 'general'
  }
}

try {
  const carData  = $('CAR Coverage Lookup').first().json;
  techniques     = carData.techniques    || techniques;  // enriched with coverage
  coverageGaps   = carData.coverage_gaps || [];
  lowCoverage    = carData.low_coverage  || [];
  analystFindings = carData.analyst_findings || analystFindings;
} catch (e) {
  // CAR node may not be in pipeline yet — degrade gracefully
}

try {
  const nistData = $('NIST CSF Mapper').first().json;
  nistMappings   = nistData.nist_csf_mappings || [];
} catch (e) {
  nistMappings = synthesizerOutput.nist_csf_mappings || [];
}

try {
  const cisData  = $('CIS Controls Mapper').first().json;
  cisMappings    = cisData.cis_mappings    || [];
  cisQuickWins   = cisData.cis_quick_wins  || [];
} catch (e) {
  // CIS node may not be in pipeline yet — degrade gracefully
}

// Get query from the workflow trigger — DO NOT reference $('Webhook Trigger')
// which doesn't exist in sub-workflows and causes the entire try to throw
try {
  originalQuery = $('Execute Workflow Trigger').first().json.query || '';
} catch (e) {
  originalQuery = '';
}
if (!originalQuery) {
  originalQuery = synthesizerOutput.query || 'N/A';
}

// Extract synthesizer response text
const synthResponse = synthesizerOutput.response || JSON.stringify(synthesizerOutput);

// ── Helper Functions ─────────────────────────────────────────────────────────

function extractRiskLevel(text) {
  const n = text.toLowerCase();
  if (n.includes('critical')) return 'CRITICAL';
  if (n.includes('high risk') || n.includes('high severity')) return 'HIGH';
  if (n.includes('medium risk') || n.includes('medium severity') || n.includes('moderate')) return 'MEDIUM';
  if (n.includes('low risk') || n.includes('low severity')) return 'LOW';
  return 'MEDIUM';
}

function extractConfidence(text) {
  const n = text.toLowerCase();
  if (n.includes('high confidence')) return 'HIGH';
  if (n.includes('low confidence')) return 'LOW';
  return 'MEDIUM';
}

function formatMitreMappings(techs) {
  if (!techs || techs.length === 0) return '| No specific MITRE ATT&CK techniques identified.';
  return techs.map(t => {
    const covLine = t.coverage
      ? `|   Coverage: CAR=${t.coverage.car} Sigma=${t.coverage.sigma} ES_SIEM=${t.coverage.es_siem} Splunk=${t.coverage.splunk} Total=${t.coverage.total}`
      : '';
    return [
      `| ${t.id} | ${t.name} | ${(t.tactics || []).join(', ')} |`,
      `|   Description: ${t.description || ''}`,
      `|   Detection: ${t.detection || ''}`,
      covLine,
    ].filter(Boolean).join('\n');
  }).join('\n');
}

function formatNistMappings(mappings) {
  if (!mappings || mappings.length === 0) return '| No specific NIST CSF 2.0 mappings identified.';
  return mappings.map(func => {
    const cats = (func.categories || []).map(cat => {
      const subs = (cat.relevant_subcategories || [])
        .slice(0, 3)
        .map(s => `|     - ${s.id}: ${s.description}`)
        .join('\n');
      return `|   ${cat.category_id} - ${cat.category_name}\n|     ${cat.description}${subs ? '\n' + subs : ''}`;
    }).join('\n');
    return `| ${func.function_id} (${func.function_name}):\n${cats}`;
  }).join('\n\n');
}

function formatDetectionGaps(techs, gaps, low) {
  const lines = ['| Based on identified techniques, the following detection capabilities should be verified:'];

  for (const t of techs.slice(0, 5)) {
    lines.push(`| - ${t.id} (${t.name}): ${t.detection || 'See MITRE ATT&CK for detection guidance'}`);
  }

  if (gaps && gaps.length > 0) {
    lines.push('|');
    lines.push(`| ⚠️  ZERO-COVERAGE TECHNIQUES (${gaps.length}) — no community detection rules exist:`);
    for (const g of gaps) {
      lines.push(`|   ⚠️  ${g.id} (${g.name}): CAR=0 Sigma=0 ES SIEM=0 Splunk=0 — custom detection rules required`);
    }
  }

  if (low && low.length > 0) {
    lines.push('|');
    lines.push(`| ⚠️  LOW-COVERAGE TECHNIQUES (${low.length}) — very few community detections (total < 5):`);
    for (const l of low) {
      lines.push(`|   ${l.id} (${l.name}): Total=${l.coverage.total} (CAR=${l.coverage.car} Sigma=${l.coverage.sigma})`);
    }
  }

  return lines.join('\n');
}

function formatAnalyticCoverage(techs) {
  if (!techs || !techs.some(t => t.coverage)) {
    return '| CAR analytic coverage data not available for this pipeline run.';
  }
  const lines = ['| Analytic coverage per identified technique (CAR / Sigma / ES SIEM / Splunk):'];
  for (const t of techs) {
    if (!t.coverage) continue;
    const total   = t.coverage.total;
    const flag    = total === 0 ? ' ⚠️  NO DETECTIONS' : total < 5 ? ' ⚠️  LOW COVERAGE' : '';
    lines.push(`| ${t.id} (${t.name}): CAR=${t.coverage.car} Sigma=${t.coverage.sigma} ES SIEM=${t.coverage.es_siem} Splunk=${t.coverage.splunk} — Total: ${total}${flag}`);
  }
  return lines.join('\n');
}

function formatCisControls(mappings, quickWins) {
  const lines = [];

  if (quickWins && quickWins.length > 0) {
    lines.push('| Quick Wins — Implementation Group 1 (applicable to all organizations):');
    for (const sg of quickWins) {
      const igs = (sg.implementation_groups || ['IG1']).join('/');
      lines.push(`|   [${sg.id}] ${sg.title} [${igs}] — CIS Control ${sg.control_id}: ${sg.control_title}`);
    }
  }

  if (mappings && mappings.length > 0) {
    lines.push('|');
    lines.push('| Recommended controls by CIS Control number:');
    for (const ctrl of mappings) {
      lines.push(`| CIS Control ${ctrl.control_id} — ${ctrl.control_title}:`);
      for (const sg of (ctrl.safeguards || [])) {
        const igs = (sg.implementation_groups || []).join('/');
        const fn  = sg.security_function ? ` [${sg.security_function}]` : '';
        lines.push(`|   [${sg.id}] ${sg.title} [${igs}]${fn}`);

      }
    }
  }

  if (lines.length === 0) {
    return '| CIS Controls mapping not available for this pipeline run.';
  }

  return lines.join('\n');
}

// ── Report Assembly ───────────────────────────────────────────────────────────

const typeDisplayNames = {
  'auth_anomaly':              'Authentication Anomaly Investigation',
  'beaconing':                 'Beaconing / C2 Communication Investigation',
  'exfiltration':              'Data Exfiltration Investigation',
  'lateral_movement':          'Lateral Movement Investigation',
  'privilege_escalation':      'Privilege Escalation Investigation',
  'persistence':               'Persistence Mechanism Investigation',
  'ransomware':                'Ransomware Incident Investigation',
  'insider_threat':            'Insider Threat Investigation',
  'vulnerability_exploitation':'Vulnerability Exploitation Investigation',
  'general':                   'General Security Investigation',
};

const riskLevel  = extractRiskLevel(synthResponse);
const confidence = extractConfidence(synthResponse);
const timestamp  = new Date().toISOString();

const report = `
================================================================================
NIST SP 800-92 ALIGNED INVESTIGATION REPORT
Generated: ${timestamp}
Frameworks: MITRE ATT&CK | NIST CSF 2.0 | CIS Controls v8.1.2 | MITRE CAR Coverage
================================================================================

1. EXECUTIVE SUMMARY
--------------------------------------------------------------------------------
| Query: ${originalQuery}
| Investigation Type: ${typeDisplayNames[investigationType] || investigationType}
| Risk Level: ${riskLevel}
| Confidence: ${confidence}
| MITRE Techniques Identified: ${techniques.length}
| NIST CSF Functions Mapped: ${nistMappings.length}
| CIS Controls Recommended: ${cisMappings.length} controls, ${cisQuickWins.length} quick wins
| Detection Coverage Gaps: ${coverageGaps.length} techniques with zero detections
|
| Summary:
${synthResponse.split('\n').slice(0, 5).map(l => '| ' + l).join('\n')}

2. INCIDENT CLASSIFICATION (NIST CSF 2.0)
--------------------------------------------------------------------------------
${formatNistMappings(nistMappings)}

3. TECHNICAL FINDINGS
--------------------------------------------------------------------------------
${synthResponse.split('\n').map(l => '| ' + l).join('\n')}

4. MITRE ATT&CK MAPPING
--------------------------------------------------------------------------------
${formatMitreMappings(techniques)}

5. DETECTION GAPS & RECOMMENDATIONS
--------------------------------------------------------------------------------
${formatDetectionGaps(techniques, coverageGaps, lowCoverage)}

5.5 ANALYTIC COVERAGE (MITRE CAR / Sigma / ES SIEM / Splunk)
--------------------------------------------------------------------------------
${formatAnalyticCoverage(techniques)}

5.6 CIS CONTROLS v8.1.2 RECOMMENDATIONS
--------------------------------------------------------------------------------
${formatCisControls(cisMappings, cisQuickWins)}

6. RECOMMENDED ACTIONS
--------------------------------------------------------------------------------
| Priority actions based on risk level (${riskLevel}):
| [See detailed recommendations in Technical Findings section above]
| [See CIS Controls quick wins in Section 5.6 for implementation guidance]

7. CONFIDENCE ASSESSMENT
--------------------------------------------------------------------------------
| Overall Confidence: ${confidence}
| Techniques Matched: ${techniques.length} (deterministic lookup against MITRE ATT&CK database)
| NIST Functions Covered: ${nistMappings.map(m => m.function_id).join(', ') || 'None'}
| CIS Controls Matched: ${cisMappings.map(c => 'CIS-' + c.control_id).join(', ') || 'None'}
| Coverage Gaps Identified: ${coverageGaps.length} techniques with no community detections
| Data Gaps: [See analyst findings for specific data gap notes]

8. EVIDENCE CHAIN
--------------------------------------------------------------------------------
| Investigation Flow:
| 1. Query received and classified as: ${investigationType}
| 2. Routed to specialized analyst agents
| 3. Findings matched against ${techniques.length > 0 ? techniques.length : 'N/A'} MITRE ATT&CK techniques
| 4. Detection coverage enriched from MITRE CAR analytic coverage dataset
| 5. Mapped to ${nistMappings.length} NIST CSF 2.0 function areas
| 6. Mapped to ${cisMappings.length} CIS Controls v8.1.2 control groups
| 7. Purple team validation and synthesis completed
| 8. Report generated per NIST SP 800-92 guidelines

================================================================================
END OF REPORT | CASA CyberAnalysis System | ${timestamp}
================================================================================
`.trim();

return [{
  json: {
    status: 'complete',
    investigation_report: report,
    risk_level: riskLevel,
    confidence: confidence,
    mitre_techniques:    techniques.map(t => ({ id: t.id, name: t.name, tactics: t.tactics, description: t.description || '', detection: t.detection || '', coverage: t.coverage || null })),
    nist_csf_functions:  nistMappings.map(m => m.function_id),
    cis_controls:        cisMappings.map(c => ({ control_id: c.control_id, control_title: c.control_title })),
    coverage_gaps:       coverageGaps.map(g => g.id),
    query:               originalQuery,
    investigation_type:  investigationType,
    timestamp:           timestamp,
  }
}];

const fs = require('fs');
const coverageData = JSON.parse(
  fs.readFileSync('/home/node/assets/car-analytic-coverage.json', 'utf8')
);
const coverageMap = new Map();
for (const tech of coverageData.techniques) {
  coverageMap.set(tech.id, tech.coverage);
}
const inputData = $input.first().json;
const techniques        = inputData.techniques        || [];
const investigationType = inputData.investigation_type || 'general';
const analystFindings   = inputData.analyst_findings   || '';

const enrichedTechniques = techniques.map(t => {
  const coverage = coverageMap.get(t.id) || { car: 0, sigma: 0, es_siem: 0, splunk: 0, total: 0 };
  return { ...t, coverage };
});

const coverageGaps = enrichedTechniques.filter(t => t.coverage.total === 0).map(t => ({
  id: t.id, name: t.name, tactics: t.tactics, coverage: t.coverage,
}));

const lowCoverage = enrichedTechniques.filter(t => t.coverage.total > 0 && t.coverage.total < 5).map(t => ({
  id: t.id, name: t.name, tactics: t.tactics, coverage: t.coverage,
}));

return [{
  json: {
    techniques: enrichedTechniques,
    coverage_gaps: coverageGaps,
    low_coverage: lowCoverage,
    coverage_db_version: coverageData.version,
    investigation_type: investigationType,
    analyst_findings: analystFindings,
    technique_count: techniques.length,
  }
}];

const fs = require('fs');

// Load CIS Controls data
const cisData = JSON.parse(
  fs.readFileSync('/home/node/assets/cis-controls-v8.1.2.json', 'utf8')
);

// Load technique-to-controls deterministic mapping
let techniqueMap = {};
try {
  const mapData = JSON.parse(
    fs.readFileSync('/home/node/assets/mitre-to-controls-map.json', 'utf8')
  );
  for (const m of mapData.mappings) {
    techniqueMap[m.technique_id] = {
      cis_safeguards: m.cis_safeguards,
      nist_csf_categories: m.nist_csf_categories
    };
  }
} catch (e) {
  // Mapping file not available — fall back to keyword-only matching
}

const inputData = $input.first().json;
const findings     = inputData.analyst_findings  || JSON.stringify(inputData);
const techniques   = inputData.techniques        || [];
const nistMappings = inputData.nist_csf_mappings || [];
const coverageGaps = inputData.coverage_gaps     || [];
const lowCoverage  = inputData.low_coverage      || [];

// ── Step 1: Deterministic mapping from identified techniques ──
// This is the PRIMARY source — directly maps MITRE techniques to CIS safeguards
const techniqueMatchedSafeguards = new Set();

for (const tech of techniques) {
  const mapping = techniqueMap[tech.id];
  if (mapping) {
    for (const sgId of mapping.cis_safeguards) {
      techniqueMatchedSafeguards.add(sgId);
    }
  }
}

// ── Step 2: Keyword supplement for additional coverage ──
const normalizedFindings = findings.toLowerCase()
  .replace(/[^a-z0-9\s\-\.]/g, ' ').replace(/\s+/g, ' ').trim();

const tacticToCisFunction = {
  'Initial Access': ['Protect'], 'Execution': ['Protect', 'Detect'],
  'Persistence': ['Protect', 'Detect'], 'Privilege Escalation': ['Protect', 'Identify'],
  'Defense Evasion': ['Detect', 'Protect'], 'Credential Access': ['Protect', 'Identify'],
  'Discovery': ['Identify', 'Detect'], 'Lateral Movement': ['Protect', 'Detect'],
  'Collection': ['Protect', 'Detect'], 'Command and Control': ['Detect', 'Respond'],
  'Exfiltration': ['Detect', 'Respond', 'Protect'], 'Impact': ['Respond', 'Recover'],
};
const observedTactics = new Set();
for (const tech of techniques) for (const tactic of (tech.tactics || [])) observedTactics.add(tactic);

// ── Step 3: Score safeguards ──
const safeguardScores = [];
for (const control of cisData.controls) {
  for (const sg of control.safeguards) {
    let score = 0;
    let matchSource = [];

    // Deterministic technique mapping (highest weight)
    if (techniqueMatchedSafeguards.has(sg.id)) {
      score += 5;
      matchSource.push('technique-map');
    }

    // Keyword matching (supplement)
    for (const kw of (sg.keywords || [])) {
      if (normalizedFindings.includes(kw.toLowerCase())) score += 1;
    }
    if (normalizedFindings.includes(sg.title.toLowerCase())) score += 2;

    // Tactic-function correlation
    const secFunc = sg.security_function || '';
    for (const tactic of observedTactics) {
      const fns = tacticToCisFunction[tactic] || [];
      if (fns.some(f => f.toLowerCase() === secFunc.toLowerCase())) score += 0.5;
    }

    // Coverage gap boost
    if (coverageGaps.length > 0 && secFunc.toLowerCase() === 'detect') {
      score += coverageGaps.length * 0.25;
    }

    if (score > 0) {
      safeguardScores.push({
        control_id: control.id, control_title: control.title,
        safeguard_id: sg.id, safeguard_title: sg.title, description: sg.description,
        asset_type: sg.asset_type, security_function: sg.security_function,
        nist_csf_function: sg.nist_csf_function, implementation_groups: sg.implementation_groups,
        score, match_source: matchSource,
      });
    }
  }
}

safeguardScores.sort((a, b) => b.score - a.score);
const topSafeguards = safeguardScores.slice(0, 15);
const byControl = {};
for (const sg of topSafeguards) {
  if (!byControl[sg.control_id]) {
    byControl[sg.control_id] = {
      control_id: sg.control_id, control_title: sg.control_title, safeguards: []
    };
  }
  byControl[sg.control_id].safeguards.push({
    id: sg.safeguard_id, title: sg.safeguard_title,
    description: sg.description, asset_type: sg.asset_type,
    security_function: sg.security_function,
    nist_csf_function: sg.nist_csf_function,
    implementation_groups: sg.implementation_groups
  });
}
const cisMappings = Object.values(byControl).sort((a, b) => a.control_id - b.control_id);
const quickWins = topSafeguards
